const agora = Date.now();
const MS_DIA = 24 * 60 * 60 * 1000;

// D+3: enviou entre 3 e 4 dias atrás
const d3_inicio = String(agora - 4 * MS_DIA);
const d3_fim = String(agora - 3 * MS_DIA);

// D+7: enviou entre 7 e 8 dias atrás
const d7_inicio = String(agora - 8 * MS_DIA);
const d7_fim = String(agora - 7 * MS_DIA);

// D+14: enviou entre 14 e 15 dias atrás — marcar como frio
const d14_inicio = String(agora - 15 * MS_DIA);
const d14_fim = String(agora - 14 * MS_DIA);

return [{ json: { d3_inicio, d3_fim, d7_inicio, d7_fim, d14_inicio, d14_fim } }];

const result = $json;
if (!result.results || result.results.length === 0) return [];
return result.results.map(deal => ({ json: { dealId: deal.id, dealName: deal.properties.dealname, contatoNome: deal.properties.contato_nome || '', contatoWhatsapp: deal.properties.contato_whatsapp, segmento: deal.properties.segmento || '', sdrHistorico: deal.properties.sdr_historico || '[]', sdrTentativas: parseInt(deal.properties.sdr_tentativas || '1'), sdrPontoDor: deal.properties.sdr_ponto_dor || '', sdrGancho: deal.properties.sdr_gancho || '', tipoFollowup: 'D3', novoEstado: 'FOLLOWUP_1' } }));

const result = $json;
if (!result.results || result.results.length === 0) return [];
return result.results.map(deal => ({ json: { dealId: deal.id, dealName: deal.properties.dealname, contatoNome: deal.properties.contato_nome || '', contatoWhatsapp: deal.properties.contato_whatsapp, segmento: deal.properties.segmento || '', sdrHistorico: deal.properties.sdr_historico || '[]', sdrTentativas: parseInt(deal.properties.sdr_tentativas || '2'), sdrPontoDor: deal.properties.sdr_ponto_dor || '', sdrGancho: deal.properties.sdr_gancho || '', tipoFollowup: 'D7', novoEstado: 'FOLLOWUP_2' } }));

const result = $json;
if (!result.results || result.results.length === 0) return [];
return result.results.map(deal => ({ json: { dealId: deal.id, dealName: deal.properties.dealname, contatoNome: deal.properties.contato_nome || '', contatoWhatsapp: deal.properties.contato_whatsapp, sdrHistorico: deal.properties.sdr_historico || '[]', sdrPontoDor: deal.properties.sdr_ponto_dor || '', tipoFollowup: 'D14_FRIO', novoEstado: 'LEAD_FRIO' } }));

const d = $json;

let contextoFollowup = '';
if (d.tipoFollowup === 'D3') {
  contextoFollowup = `Esta é a SEGUNDA mensagem (D+3 sem resposta). O lead recebeu o primeiro contato há 3 dias e não respondeu.
  Tom: curto, leve, sem pressão. Aborde um ângulo diferente do primeiro contato. Pode referenciar o ponto de dor de forma diferente. Termine com pergunta de abertura.`;
} else {
  contextoFollowup = `Esta é a TERCEIRA mensagem (D+7 sem resposta). O lead recebeu 2 mensagens anteriores e não respondeu.
  Tom: último toque antes de encerrar. Seja honesto: "só mais uma vez antes de tirar da fila". Pode mencionar que entende que o momento pode não ser o ideal. Pergunta simples e direta.`;
}

const system = `Você é NOVA, representante comercial da Carbon Films.

REGRAS:
- Inicie com [NOVA]:
- Máximo 2 parágrafos curtos
- Uma pergunta por mensagem
- Sem pressão, sem urgência falsa
- NÃO use markdown
- NÃO mencione preço

Responda SOMENTE com o texto da mensagem, pronto para enviar.`;

const user = `Escreva um follow-up para:
- Nome: ${d.contatoNome || d.dealName}
- Empresa: ${d.dealName}
- Segmento: ${d.segmento || 'negócio em SC'}
- Ponto de dor original: ${d.sdrPontoDor || 'comunicação visual'}

${contextoFollowup}`;

return [{
  json: {
    ...d,
    claudeBody: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 250,
      system,
      messages: [{ role: 'user', content: user }]
    })
  }
}];

const response = $json;
const prev = $('Gerar Follow-up com NOVA').first().json;

let mensagem = '';
try {
  mensagem = response.content[0].text.trim().replace(/\*\*/g, '').replace(/^#+\s/gm, '');
} catch(e) {
  if (prev.tipoFollowup === 'D3') {
    mensagem = `[NOVA]: Oi, ${prev.contatoNome || 'tudo bem'}! Passei para ver se surgiu alguma dúvida sobre o que conversei semana passada. Ainda faz sentido o que te mencionei?`;
  } else {
    mensagem = `[NOVA]: Oi, ${prev.contatoNome || 'tudo bem'}! Só mais um toque antes de tirar da fila. Se o momento não for ideal agora, sem problemas — posso retornar quando fizer sentido. O desafio que te mencionei ainda existe?`;
  }
}

// Atualizar histórico
let historico = [];
try { historico = JSON.parse(prev.sdrHistorico || '[]'); } catch(e) {}
historico.push({ role: 'nova', content: mensagem, action: 'followup_' + prev.tipoFollowup.toLowerCase(), estado: prev.novoEstado, note: 'Follow-up automático ' + prev.tipoFollowup, ts: new Date().toISOString() });
if (historico.length > 30) historico = historico.slice(-30);

return [{
  json: {
    ...prev,
    mensagemFollowup: mensagem,
    whatsappBody: JSON.stringify({ to: prev.contatoWhatsapp, type: 'text', text: { body: mensagem } }),
    hubspotBody: JSON.stringify({ properties: { sdr_estado: prev.novoEstado, sdr_historico: JSON.stringify(historico), sdr_tentativas: String(prev.sdrTentativas + 1), sdr_ultimo_contato: String(Date.now()), dealstage: $vars.HUBSPOT_STAGE_EM_CONVERSA } }),
    noteBody: JSON.stringify({ properties: { hs_note_body: `[NOVA SDR - ${prev.tipoFollowup}] Follow-up automático enviado.\n\nMensagem:\n${mensagem}`, hs_timestamp: String(Date.now()) }, associations: [{ to: { id: prev.dealId }, types: [{ associationCategory: 'HUBSPOT_DEFINED', associationTypeId: 214 }] }] })
  }
}];
